import { nanoid } from 'nanoid';
import React, { useState } from 'react';
import './TodoAdd.css';

const TodoAdd = ({todos, setTodos}) => {

    const [inputText, setInputText] = useState('');

    const addTodo = () => {
        const todo = {
            "text": inputText,
            "isComplete": false,
            "id": nanoid()
        }
        setTodos([...todos, todo])
        setInputText('');
    }

    return(
        <div className='todoadd'>
            <input className='todoadd__input' value={inputText} onChange={e => setInputText(e.target.value)} placeholder='Text...'/>
            <button className='todoadd__btn' onClick={addTodo}>Add Todo</button>
        </div>
    )
}

export default TodoAdd;