import React from 'react';
import './TodoTab.css';

const TodoTab = ({ text, selectedCategory, setSelectedCategory }) => {

    const selectCategory = () => {
        setSelectedCategory(text);
    }

    return (
        <li onClick={selectCategory} className={selectedCategory === text ? 'todotabs__item active' : 'todotabs__item'}>
            {text}
        </li>
    )
}

export default TodoTab;