import React from 'react';
import './TodoItem.css';

const TodoItem = ({ todos, setTodos, todo }) => {

    const setTodoStatus = () => {
        setTodos(todos.map(item => {
            if (item.id == todo.id) {
                item.isComplete = !item.isComplete;
                return item
            } else {
                return item
            }
        }))
    }

    const deleteTodo = () => {
        console.log(todo);
        setTodos(todos.filter(item => item.id !== todo.id));
    }

    return (
        <div className={todo.isComplete ? "todo completed" : "todo"}>
            <button onClick={deleteTodo} className='todo__delete'>
                <svg width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <path d="M2.5 5H4.16667H17.5" stroke="#999999" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" />
                    <path d="M6.66602 5.00033V3.33366C6.66602 2.89163 6.84161 2.46771 7.15417 2.15515C7.46673 1.84259 7.89065 1.66699 8.33268 1.66699H11.666C12.108 1.66699 12.532 1.84259 12.8445 2.15515C13.1571 2.46771 13.3327 2.89163 13.3327 3.33366V5.00033M15.8327 5.00033V16.667C15.8327 17.109 15.6571 17.5329 15.3445 17.8455C15.032 18.1581 14.608 18.3337 14.166 18.3337H5.83268C5.39065 18.3337 4.96673 18.1581 4.65417 17.8455C4.34161 17.5329 4.16602 17.109 4.16602 16.667V5.00033H15.8327Z" stroke="#999999" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" />
                    <path d="M8.33398 9.16699V14.167" stroke="#999999" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" />
                    <path d="M11.666 9.16699V14.167" stroke="#999999" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" />
                </svg>

            </button>
            <div onClick={setTodoStatus} className='todo__complete'>
                {todo.isComplete ?
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <circle cx="12" cy="12" r="12" fill="#FFD73B" />
                        <path d="M15.8008 9L10.3008 14.5L7.80078 12" stroke="#333333" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" />
                    </svg>
                    :
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <circle cx="12" cy="12" r="11" stroke="#FFD73B" stroke-width="2" />
                    </svg>
                }
                <p className='todo__text'>{todo.text}</p>
            </div>
        </div>
    )
}

export default TodoItem;