import React from 'react';
import TodoTab from './TodoTab/TodoTab';
import './TodoTabs.css';

const TodoTabs = ({ selectedCategory, setSelectedCategory }) => {

    return (
        <div className='todotabs'>
            <ul className='todotabs__list'>
                <TodoTab selectedCategory={selectedCategory} setSelectedCategory={setSelectedCategory} text='All' />
                <TodoTab selectedCategory={selectedCategory} setSelectedCategory={setSelectedCategory} text='Completed' />
                <TodoTab selectedCategory={selectedCategory} setSelectedCategory={setSelectedCategory} text='Uncompleted' />
            </ul>
        </div>
    )
}

export default TodoTabs;