import { useEffect, useState } from 'react';
import './App.css';
import TodoAdd from './Components/TodoAdd/TodoAdd';
import TodoItem from './Components/TodoItem/TodoItem';
import TodoTabs from './Components/TodoTabs/TodoTabs';

function App() {

  const [todos, setTodos] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [filteredTodos, setFilteredTodos] = useState([]);

  const filterTodos = () => {
    switch(selectedCategory) {
      case 'All' : {
        setFilteredTodos(todos);
        break;
      }
      case 'Completed' : {
        setFilteredTodos(todos.filter(item => item.isComplete === true))
        break;
      }
      case 'Uncompleted' : {
        setFilteredTodos(todos.filter(item => item.isComplete === false))
        break;
      }
    }
  }

  const saveLocalStorage = () => {
    if (localStorage.getItem('todos') === null) {
      localStorage.setItem('todos', JSON.stringify([]));
    } else {
      localStorage.setItem('todos', JSON.stringify(todos));
    }
  }

  useEffect(() => {
    if (localStorage.getItem('todos') === null) {
      localStorage.setItem('todos', JSON.stringify([]));
    } else {
      setTodos(JSON.parse(localStorage.getItem('todos')));
    }

  },[])

  useEffect(() => {
    filterTodos();
    saveLocalStorage();
  },[todos, selectedCategory])

  return (
    <div className="App">
      <h1>ToDo App for Cater2</h1>
      <TodoAdd todos={todos} setTodos={setTodos} />
      <TodoTabs selectedCategory={selectedCategory} setSelectedCategory={setSelectedCategory} />
      <div className='todolist'>
        {filteredTodos && filteredTodos.map(item => <TodoItem todo={item} todos={todos} setTodos={setTodos} key={item.id} />)}
      </div>
    </div>
  );
}

export default App;
